#include <iostream>
#include <vector>
#include <cmath>

void renderPattern(int depth) {
    if (depth == 0) return;
    for (int i = 0; i < depth; ++i) {
        std::cout << i * 2 << " ";
    }
    std::cout << "\n";
    renderPattern(depth - 1);
}

int main() {
    int limit = 5;
    renderPattern(limit);
    return 0;
}
